    transitions[word] = sample(Dirichlet({alpha: [2, 2, 2, 2, 2]}));
  });

  // Function to transition from a word to the next word
  var transition = function(word) {
    var probs = transitions[word];
    return categorical({vs: vocab, ps: probs});
  };

